/**
 * @param {string} s
 * @return {number}
 */
function solve(s) {
    // 1. Count frequencies of all characters
    const freqMap = new Map();
    for (const char of s) {
        freqMap.set(char, (freqMap.get(char) || 0) + 1);
    }

    // Helper function to get the mirror character
    function getMirrorChar(char) {
        if (char >= 'a' && char <= 'z') {
            // Letter: 'a' -> 'z', 'b' -> 'y', ...
            const charCode = char.charCodeAt(0);
            // 'a' is 97, 'z' is 122.
            // Position from start (0-indexed): charCode - 'a'.charCodeAt(0)
            // Position from end (0-indexed): 'z'.charCodeAt(0) - (charCode - 'a'.charCodeAt(0))
            // Target charCode = 'z'.charCodeAt(0) - (charCode - 'a'.charCodeAt(0))
            const mirrorCharCode = 'z'.charCodeAt(0) - (charCode - 'a'.charCodeAt(0));
            return String.fromCharCode(mirrorCharCode);
        } else if (char >= '0' && char <= '9') {
            // Digit: '0' -> '9', '1' -> '8', ...
            const digit = parseInt(char);
            const mirrorDigit = 9 - digit;
            return String(mirrorDigit);
        }
        return null; // Should not happen based on constraints
    }

    let totalDifference = 0;
    const processedPairs = new Set();

    // 2. Iterate over unique characters to find unique mirror pairs
    for (const char of freqMap.keys()) {
        if (processedPairs.has(char)) {
            continue;
        }

        const m = getMirrorChar(char);

        if (!m) continue; // Safety check

        // Normalize the pair order to ensure we only process (c, m) once, not (m, c) again.
        // Since the problem states (c, m) and (m, c) are the same, we enforce an order.
        // We use a string key for the set, e.g., "char_mirror" where char < mirror lexicographically.
        let pairKey;
        if (char < m) {
            pairKey = `${char}_${m}`;
        } else if (m < char) {
            pairKey = `${m}_${char}`;
        } else {
            // char === m (e.g., 'm' and 'n' are mirrors, but 'z' mirrors to 'a' is false. 
            // Only self-mirroring characters would satisfy this, like if the alphabet was smaller, or 0/9 if we considered 0/9 the same)
            // For the defined mapping, a character can only mirror to itself if it's not an alphabet or digit, 
            // or if it maps to itself (e.g., 'a' -> 'z' != 'a').
            // Self-mirrors are not possible under this definition unless c=m.
            pairKey = `${char}_${m}`; 
        }

        if (processedPairs.has(pairKey)) {
            continue;
        }

        // Add both characters to processed set to avoid processing the pair again via 'm' later
        processedPairs.add(pairKey);
        processedPairs.add(`${char}_${char}`); // Use a unique marker if needed, but checking pairKey is sufficient.

        // Calculate the absolute difference
        const freqC = freqMap.get(char) || 0;
        const freqM = freqMap.get(m) || 0;

        const difference = Math.abs(freqC - freqM);
        totalDifference += difference;
    }

    return totalDifference;
}

