          val freqC = freqMap.getOrElse(char, 0)
          val freqM = freqMap.getOrElse(m, 0)

          val difference = Math.abs(freqC - freqM)
          totalDifference += difference.toLong

          // Mark both characters as processed for this pair, to prevent reprocessing when iterating on 'm'
          processedPairs.add(char.toString)
          processedPairs.add(m.toString)

