import scala.collection.mutable

object Solution {
  /**
   * Calculates the sum of absolute differences between frequency counts of characters and their mirror characters for all unique mirror pairs.
   * @param s The input string consisting of lowercase English letters and digits.
   * @return The total absolute difference sum.
   */
  def solve(s: String): Long = {
    // 1. Count frequencies of all characters
    val freqMap = mutable.Map[Char, Int]()
    for (char <- s) {
      freqMap(char) = freqMap.getOrElse(char, 0) + 1
    }

    // Helper function to get the mirror character
    def getMirrorChar(char: Char): Option[Char] = {
      if (char >= 'a' && char <= 'z') {
        // Letter: 'a' -> 'z', 'b' -> 'y', ...
        val charCode = char.toInt
