        // 'a' is 97, 'z' is 122.
        val charCode = c.toInt
        val mirrorCharCode = 'z'.toInt - (charCode - 'a'.toInt)
        Some(mirrorCharCode.toChar)
      } else if (c >= '0' && c <= '9') {
        // Digit: '0' -> '9', '1' -> '8', ...
        val digit = c.toString.toInt
        val mirrorDigit = 9 - digit
        Some(mirrorDigit.toString.head)
      } else {
        None
      }
    }

    var totalDifference: Long = 0
    val processedPairs = mutable.Set[String]()

    // 2. Iterate over unique characters to find unique mirror pairs
    val uniqueChars = freqMap.keys.toSeq.sorted // Sorting ensures deterministic iteration order

